export const getRunRetentionDeleteUrl = () => {
  return `/api/retention/delete`;
};

export const runRetentionDelete = async (
  retentionInput: RetentionInput,
  options?: RequestInit,
): Promise<RetentionResult> => {
  return customFetch<RetentionResult>(getRunRetentionDeleteUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(retentionInput),
  });
};

export const getRunRetentionDeleteMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof runRetentionDelete>>,
    TError,
    { data: BodyType<RetentionInput> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof runRetentionDelete>>,
  TError,
  { data: BodyType<RetentionInput> },
  TContext
> => {
  const mutationKey = ["runRetentionDelete"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof runRetentionDelete>>,
    { data: BodyType<RetentionInput> }
  > = (props) => {
    const { data } = props ?? {};

    return runRetentionDelete(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

